import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "../styles/Navbar.css";

const Navbar = () => {
  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate("/login");
    setMenuOpen(false);
  };

  const closeMenu = () => {
    setMenuOpen(false);
  };

  return (
    <nav className="navbar">
      <div className="container navbar-container">
        <Link to="/" className="navbar-logo" onClick={closeMenu}>
          🎪 Svet Igraonica
        </Link>

        <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          <span></span>
          <span></span>
          <span></span>
        </button>

        <div className={`navbar-links ${menuOpen ? "open" : ""}`}>
          <Link to="/" onClick={closeMenu}>
            Početna
          </Link>
          <Link to="/playrooms" onClick={closeMenu}>
            Igraonice
          </Link>

          {isAuthenticated ? (
            <>
              <span className="user-name">
                👤 {user?.ime} {user?.prezime}
              </span>
              {user?.role === "vlasnik" && (
                <>
                  <Link to="/my-playrooms" onClick={closeMenu}>
                    Moje igraonice
                  </Link>
                  <Link to="/create-playroom" onClick={closeMenu}>
                    + Dodaj igraonicu
                  </Link>
                </>
              )}
              {user?.role === "admin" && (
                <Link to="/admin" onClick={closeMenu}>
                  Admin panel
                </Link>
              )}
              // Za roditelja (kada je prijavljen)
              {user?.role === "roditelj" && (
                <Link to="/my-bookings" onClick={closeMenu}>
                  Moje rezervacije
                </Link>
              )}
              // Za vlasnika (dodaj pored ostalih)
              {user?.role === "vlasnik" && (
                <>
                  <Link to="/my-playrooms" onClick={closeMenu}>
                    Moje igraonice
                  </Link>
                  <Link to="/manage-slots" onClick={closeMenu}>
                    📅 Termini
                  </Link>
                  <Link to="/create-playroom" onClick={closeMenu}>
                    + Dodaj igraonicu
                  </Link>
                </>
              )}
              <button onClick={handleLogout} className="logout-btn">
                Odjava
              </button>
            </>
          ) : (
            <>
              <Link to="/login" onClick={closeMenu}>
                Prijava
              </Link>
              <Link to="/register" onClick={closeMenu}>
                Registracija
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
